import './App.css';
import { BrowserRouter, Route, Routes } from 'react-router';
import Layout from './ui/components/layout/Layout/Layout.tsx';
import HomePage from './ui/pages/HomePage/HomePage.tsx';
import AccommodationsPage from './ui/pages/AccommodationsPage/AccommodationsPage.tsx';
import HostsPage from './ui/pages/HostsPage/HostsPage.tsx';
import CountriesPage from './ui/pages/CountriesPage/CountriesPage.tsx';
import AccommodationDetailsPage from './ui/pages/AccommodationDetailsPage/AccommodationDetailsPage.tsx';
import HostDetailsPage from './ui/pages/HostDetailsPage/HostDetailsPage.tsx';
import CountryDetailsPage from './ui/pages/CountryDetailsPage/CountryDetailsPage.tsx';

function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path='/' element={<Layout/>}>
          <Route index element={<HomePage/>}/>
          <Route path='accommodations' element={<AccommodationsPage/>}/>
          <Route path='accommodations/:id' element={<AccommodationDetailsPage/>}/>
          <Route path='hosts' element={<HostsPage/>}/>
          <Route path='hosts/:id' element={<HostDetailsPage/>}/>
          <Route path='countries' element={<CountriesPage/>}/>
          <Route path='countries/:id' element={<CountryDetailsPage/>}/>
        </Route>
      </Routes>
    </BrowserRouter>
  );
}

export default App;

import './App.css';
import { BrowserRouter, Route, Routes } from 'react-router';
import Layout from './ui/components/layout/Layout/Layout.tsx';
import HomePage from './ui/pages/HomePage/HomePage.tsx';
import AccommodationsPage from './ui/pages/AccommodationsPage/AccommodationsPage.tsx';
import HostsPage from './ui/pages/HostsPage/HostsPage.tsx';
import CountriesPage from './ui/pages/CountriesPage/CountriesPage.tsx';
import AccommodationDetailsPage from './ui/pages/AccommodationDetailsPage/AccommodationDetailsPage.tsx';
import HostDetailsPage from './ui/pages/HostDetailsPage/HostDetailsPage.tsx';
import CountryDetailsPage from './ui/pages/CountryDetailsPage/CountryDetailsPage.tsx';
import LoginPage from './ui/pages/LoginPage/LoginPage.tsx';

function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/login" element={<LoginPage />} />
        <Route path='/' element={<Layout/>}>
          <Route index element={<HomePage/>}/>
          <Route path='accommodations' element={<AccommodationsPage/>}/>
          <Route path='accommodations/:id' element={<AccommodationDetailsPage/>}/>
          <Route path='hosts' element={<HostsPage/>}/>
          <Route path='hosts/:id' element={<HostDetailsPage/>}/>
          <Route path='countries' element={<CountriesPage/>}/>
          <Route path='countries/:id' element={<CountryDetailsPage/>}/>
        </Route>
      </Routes>
    </BrowserRouter>
  );
}

export default App;

import axiosInstance from '../axios/axios';

interface LoginResponse {
  accessToken: string;
}

const userApi = {
  login: async (email: string, password: string) => {
    const response = await axiosInstance.post<LoginResponse>('/user/login', {
      email,
      password
    });
    return response.data.accessToken;
  },
  register: async (email: string, password: string) => {
    return await axiosInstance.post('/user/register', {
      email,
      password
    });
  }
};

export default userApi;

import axiosInstance from '../axios/axios';

interface LoginResponse {
  token: string;
}

const userApi = {
  login: async (username: string, password: string) => {
    const response = await axiosInstance.post<LoginResponse>('/user/login', {
      username,
      password
    });
    return response.data.token;
  },
  register: async (username: string, password: string) => {
    return await axiosInstance.post('/user/register', {
      username,
      password
    });
  }
};

export default userApi;

// Store and manage JWT tokens in localStorage
export const tokenService = {
  getToken: () => localStorage.getItem('token'),
  setToken: (token: string) => localStorage.setItem('token', token),
  removeToken: () => localStorage.removeItem('token'),
  isTokenValid: () => !!localStorage.getItem('token')
};

import { useState } from 'react';
import { useNavigate } from 'react-router';
import { Box, Button, TextField, Container, Typography, Alert } from '@mui/material';
import userApi from '../../../api/userApi';
import { tokenService } from '../../../services/tokenService';

function LoginPage() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const token = await userApi.login(email, password);
      tokenService.setToken(token);
      navigate('/');
    } catch (err: any) {
      setError(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm">
      <Box sx={{ mt: 8, display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
        <Typography variant="h4" component="h1" gutterBottom>
          Login
        </Typography>

        {error && <Alert severity="error" sx={{ mt: 2, mb: 2, width: '100%' }}>{error}</Alert>}

        <Box component="form" onSubmit={handleLogin} sx={{ mt: 1, width: '100%' }}>
          <TextField
            margin="normal"
            required
            fullWidth
            id="email"
            label="Email Address"
            name="email"
            autoComplete="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
          <TextField
            margin="normal"
            required
            fullWidth
            name="password"
            label="Password"
            type="password"
            id="password"
            autoComplete="current-password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
          <Button
            type="submit"
            fullWidth
            variant="contained"
            sx={{ mt: 3, mb: 2 }}
            disabled={loading}
          >
            {loading ? 'Logging in...' : 'Login'}
          </Button>
        </Box>
      </Box>
    </Container>
  );
}

export default LoginPage;

import { useState } from 'react';
import { useNavigate } from 'react-router';
import { Box, Button, TextField, Container, Typography, Alert } from '@mui/material';
import userApi from '../../../api/userApi';
import { tokenService } from '../../../services/tokenService';

function LoginPage() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      console.log('Attempting login with username:', username);
      const token = await userApi.login(username, password);
      console.log('Token received:', token);
      tokenService.setToken(token);
      console.log('Token stored successfully');
      navigate('/');
    } catch (err: any) {
      console.error('Login error:', err);
      const errorMessage = err.response?.data?.message || err.message || 'Login failed';
      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm">
      <Box sx={{ mt: 8, display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
        <Typography variant="h4" component="h1" gutterBottom>
          Login
        </Typography>

        {error && <Alert severity="error" sx={{ mt: 2, mb: 2, width: '100%' }}>{error}</Alert>}

        <Box component="form" onSubmit={handleLogin} sx={{ mt: 1, width: '100%' }}>
          <TextField
            margin="normal"
            required
            fullWidth
            id="username"
            label="Username"
            name="username"
            autoComplete="username"
            value={username}
            onChange={(e) => setUsername(e.target.value)}
          />
          <TextField
            margin="normal"
            required
            fullWidth
            name="password"
            label="Password"
            type="password"
            id="password"
            autoComplete="current-password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
          <Button
            type="submit"
            fullWidth
            variant="contained"
            sx={{ mt: 3, mb: 2 }}
            disabled={loading}
          >
            {loading ? 'Logging in...' : 'Login'}
          </Button>
          <Typography variant="body2" sx={{ mt: 2, color: 'gray' }}>
            Test credentials: username: testuser | password: testpassword
          </Typography>
        </Box>
      </Box>
    </Container>
  );
}

export default LoginPage;
